1	type Cell = [number, number];
2	
3	export const nextGeneration = (cells: Cell[]): Cell[] => {
4	  const key = (x: number, y: number): string => `${x},${y}`;
5	  const living = new Set<string>(cells.map(([x, y]) => key(x, y)));
6	  const neighborCounts = new Map<string, number>();
7	
8	  for (const [x, y] of cells) {
9	    for (let dx = -1; dx <= 1; dx++) {
10	      for (let dy = -1; dy <= 1; dy++) {
11	        if (dx === 0 && dy === 0) continue;
12	        const nx = x + dx;
13	        const ny = y + dy;
14	        const k = key(nx, ny);
15	        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
16	      }
17	    }
18	  }
19	
20	  const result: Cell[] = [];
21	  for (const [k, count] of neighborCounts) {
22	    const [xStr, yStr] = k.split(",");
23	    const x = Number(xStr);
24	    const y = Number(yStr);
25	    const isAlive = living.has(k);
26	    if (isAlive && (count === 2 || count === 3)) {
27	      result.push([x, y]);
28	    } else if (!isAlive && count === 3) {
29	      result.push([x, y]);
30	    }
31	  }
32	
33	  return result;
34	};
